#!/usr/bin/env python3
# Diagnostic: does the resonance semantic key survive large-model anisotropy?
# Compares RAW cosine vs MEAN-CENTERED cosine (subtract the per-file activation mean,
# i.e. remove the common-mode "rogue dimension") on the common g1-gN subset.
# Usage: centered-cosine-diag.py acts_A.json acts_B.json
import json, sys, numpy as np
from itertools import combinations
GROUPS=['g1_paris','g2_math','g3_sky','g4_freeze']
def load(f):
    d=json.load(open(f)); return d['records'], d['hidden_dim']
def cos(a,b): return float(a@b/(np.linalg.norm(a)*np.linalg.norm(b)))
def texts(recs,g): return set(x['text'] for x in recs if x['group']==g)
def run(name, recs, D, common, groups, center):
    acts={g:[np.array(x['activation'],float) for x in recs if x['group']==g and x['text'] in common[g]] for g in groups}
    if center:
        allv=np.array([v for g in groups for v in acts[g]]); mu=allv.mean(0)
        acts={g:[v-mu for v in acts[g]] for g in groups}
    within=np.array([cos(a,b) for g in groups for a,b in combinations(acts[g],2)])
    across=np.array([cos(acts[gi][ai],acts[gj][aj]) for i,gi in enumerate(groups) for gj in groups[i+1:] for ai in range(len(acts[gi])) for aj in range(len(acts[gj]))])
    acc=100*sum(w>a for w in within for a in across)/(len(within)*len(across))
    tag="CENTERED" if center else "RAW     "
    print(f"  {tag} {name} D={D}: sep={within.mean()-across.mean():+.3f} acc={acc:.1f}% "
          f"clean-margin={within.min()-across.max():+.3f} [w={within.mean():.3f} a={across.mean():.3f}]")
rA,DA=load(sys.argv[1]); rB,DB=load(sys.argv[2])
common={g:texts(rA,g)&texts(rB,g) for g in GROUPS}
groups=[g for g in GROUPS if len(common[g])>=2]
print("groups:",groups)
for center in (False,True):
    run(sys.argv[1],rA,DA,common,groups,center)
    run(sys.argv[2],rB,DB,common,groups,center)
